Create the `extension-tools.ts` file with the `list_extensions` handler and register it in `mcp-server.ts`. This file will be the home for all 6 extension MCP tool handlers.

## File: `apps/server/src/services/runtimes/claude-code/mcp-tools/extension-tools.ts` (NEW)

```typescript
import { z } from 'zod';
import type { McpToolDeps } from './types.js';
import { jsonContent } from './types.js';

/**
 * Guard that checks if the extension manager is available.
 * Returns the manager if present, or an error response if not.
 */
function requireExtensionManager(deps: McpToolDeps) {
  if (!deps.extensionManager) {
    return null;
  }
  return deps.extensionManager;
}

/**
 * Handler factory for `list_extensions` â€” lists all discovered extensions
 * with their status, scope, and errors.
 */
export function createListExtensionsHandler(deps: McpToolDeps) {
  return async () => {
    const manager = requireExtensionManager(deps);
    if (!manager) {
      return jsonContent({ error: 'Extension system is not available' }, true);
    }
    const extensions = manager.listPublic().map((ext) => ({
      id: ext.id,
      name: ext.manifest.name,
      version: ext.manifest.version,
      status: ext.status,
      scope: ext.scope,
      bundleReady: ext.bundleReady,
      ...(ext.manifest.description && { description: ext.manifest.description }),
      ...(ext.error && { error: ext.error }),
    }));
    return jsonContent({ extensions, count: extensions.length });
  };
}
```

The response includes per-extension: `id`, `name` (from manifest), `version` (from manifest), `status` (ExtensionStatus enum value), `scope` (`'global'` or `'local'`), `bundleReady` (boolean), optionally `description` (from manifest) and `error` (structured error object with `code`, `message`, `details`). The `path` field from `ExtensionRecord` is intentionally excluded from the MCP response to avoid exposing server-internal filesystem details.

