## File: `apps/server/src/services/runtimes/claude-code/mcp-tools/extension-tools.ts`

Add the handler factory:

```typescript
/**
 * Handler factory for `create_extension` â€” scaffolds a new extension
 * with manifest and working starter code.
 */
export function createCreateExtensionHandler(deps: McpToolDeps) {
  return async (args: {
    name: string;
    description?: string;
    template?: 'dashboard-card' | 'command' | 'settings-panel';
    scope?: 'global' | 'local';
  }) => {
    const manager = requireExtensionManager(deps);
    if (!manager) {
      return jsonContent({ error: 'Extension system is not available' }, true);
    }

    try {
      const result = await manager.createExtension({
        name: args.name,
        description: args.description,
        template: args.template ?? 'dashboard-card',
        scope: args.scope ?? 'local',
      });

      return jsonContent({
        created: true,
        ...result,
        message: result.bundleReady
          ? `Extension '${result.id}' created and compiled successfully. Edit index.ts and call reload_extensions to see changes.`
          : `Extension '${result.id}' created but compilation failed. Check the error and fix index.ts.`,
      });
    } catch (err) {
      return jsonContent(
        { error: err instanceof Error ? err.message : 'Failed to create extension' },
        true
      );
    }
  };
}
```

