/**
 * Compile an extension and activate it against a mock API to verify
 * it loads without errors. Returns the contribution counts per slot.
 *
 * @param id - Extension identifier
 * @returns Test result with contribution counts or error details
 */
async testExtension(id: string): Promise<TestExtensionResult> {
  const record = this.extensions.get(id);
  if (!record) {
    throw new Error(`Extension '${id}' not found`);
  }

  // Step 1: Compile
  const compileResult = await this.compiler.compile(record);
  if ('error' in compileResult) {
    return {
      status: 'error',
      id,
      phase: 'compilation',
      errors: compileResult.error.errors,
    };
  }

  // Step 2: Read the compiled bundle
  const bundle = await this.compiler.readBundle(id, compileResult.sourceHash);
  if (!bundle) {
    return {
      status: 'error',
      id,
      phase: 'compilation',
      error: 'Compiled bundle not found in cache',
    };
  }

  // Step 3: Evaluate the bundle and extract activate()
  try {
    // Create a data URI for dynamic import
    const dataUri = `data:text/javascript;base64,${Buffer.from(bundle).toString('base64')}`;
    const module = await import(/* webpackIgnore: true */ dataUri);

    if (typeof module.activate !== 'function') {
      return {
        status: 'error',
        id,
        phase: 'activation',
        error: 'Extension does not export an activate() function',
      };
    }

    // Step 4: Activate against mock API
    const mockApi = new MockExtensionAPI(id);
    module.activate(mockApi);

    const totalContributions = Object.values(mockApi.getContributions()).reduce(
      (sum, count) => sum + (count as number),
      0
    );

    return {
      status: 'ok',
      id,
      contributions: mockApi.getContributions() as Record<ExtensionPointId, number>,
      message: `Extension activated successfully. Registered ${totalContributions} contribution(s).`,
    };
  } catch (err) {
    return {
      status: 'error',
      id,
      phase: 'activation',
      error: err instanceof Error ? err.message : String(err),
      stack: err instanceof Error ? err.stack : undefined,
    };
  }
}
```

## Server-Side Activation Notes

Extensions are compiled as ESM browser bundles with `react` and `react-dom` externalized. The server-side `testExtension()` evaluates the bundle in a limited Node.js context. React component constructors will not be called â€” only the `activate()` function runs. `registerComponent` receives an opaque value (the component function) but does not attempt to render it. This is sufficient for verifying that:

1. The extension compiles without TypeScript errors
2. The `activate()` function runs without throwing
3. The expected registration methods are called for the expected slots

If the data URI `import()` approach fails in Node.js (some configurations require `--experimental-vm-modules`), fall back to `new Function()` evaluation or write the bundle to a temp file and import it.

